// OnConflict allows configuring the `ON CONFLICT` / `ON DUPLICATE KEY` clause
// of the `INSERT` statement. For example:
//
//	client.PaymentProfile.CreateBulk(builders...).
//		OnConflict(
//			// Update the row with the new values
//			// the was proposed for insertion.
//			sql.ResolveWithNewValues(),
//		).
//		// Override some of the fields with custom
//		// update values.
//		Update(func(u *ent.PaymentProfileUpsert) {
//			SetCreatedAt(v+v).
//		}).
//		Exec(ctx)
func (ppcb *PaymentProfileCreateBulk) OnConflict(opts ...sql.ConflictOption) *PaymentProfileUpsertBulk {
	ppcb.conflict = opts
	return &PaymentProfileUpsertBulk{
		create: ppcb,
	}
}

// OnConflictColumns calls `OnConflict` and configures the columns
// as conflict target. Using this option is equivalent to using:
//
//	client.PaymentProfile.Create().
//		OnConflict(sql.ConflictColumns(columns...)).
//		Exec(ctx)
func (ppcb *PaymentProfileCreateBulk) OnConflictColumns(columns ...string) *PaymentProfileUpsertBulk {
	ppcb.conflict = append(ppcb.conflict, sql.ConflictColumns(columns...))
	return &PaymentProfileUpsertBulk{
		create: ppcb,
	}
}

// PaymentProfileUpsertBulk is the builder for "upsert"-ing
// a bulk of PaymentProfile nodes.
type PaymentProfileUpsertBulk struct {
	create *PaymentProfileCreateBulk
}

// UpdateNewValues updates the mutable fields using the new values that
// were set on create. Using this option is equivalent to using:
//
//	client.PaymentProfile.Create().
//		OnConflict(
//			sql.ResolveWithNewValues(),
//			sql.ResolveWith(func(u *sql.UpdateSet) {
//				u.SetIgnore(paymentprofile.FieldID)
//			}),
//		).
//		Exec(ctx)
func (u *PaymentProfileUpsertBulk) UpdateNewValues() *PaymentProfileUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithNewValues())
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(s *sql.UpdateSet) {
		for _, b := range u.create.builders {
			if _, exists := b.mutation.ID(); exists {
				s.SetIgnore(paymentprofile.FieldID)
			}
			if _, exists := b.mutation.CreatedAt(); exists {
				s.SetIgnore(paymentprofile.FieldCreatedAt)
			}
			if _, exists := b.mutation.UserID(); exists {
				s.SetIgnore(paymentprofile.FieldUserID)
			}
			if _, exists := b.mutation.PanMasked(); exists {
				s.SetIgnore(paymentprofile.FieldPanMasked)
			}
			if _, exists := b.mutation.Holder(); exists {
				s.SetIgnore(paymentprofile.FieldHolder)
			}
		}
	}))
	return u
}

// Ignore sets each column to itself in case of conflict.
// Using this option is equivalent to using:
//
//	client.PaymentProfile.Create().
//		OnConflict(sql.ResolveWithIgnore()).
//		Exec(ctx)
func (u *PaymentProfileUpsertBulk) Ignore() *PaymentProfileUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithIgnore())
	return u
}

// DoNothing configures the conflict_action to `DO NOTHING`.
// Supported only by SQLite and PostgreSQL.
func (u *PaymentProfileUpsertBulk) DoNothing() *PaymentProfileUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.DoNothing())
	return u
}

// Update allows overriding fields `UPDATE` values. See the PaymentProfileCreateBulk.OnConflict
// documentation for more info.
func (u *PaymentProfileUpsertBulk) Update(set func(*PaymentProfileUpsert)) *PaymentProfileUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(update *sql.UpdateSet) {
		set(&PaymentProfileUpsert{UpdateSet: update})
	}))
	return u
}

